mapper.select:
SELECT p.product_id as ID, p.product_id as product_id, p.product_name as name, p.description as description, p.brand as brand, p.category_name as category_name, p.primary_image_url as image_url, p.base_price as price, p.selling_price as selling_price, CASE WHEN p.stock_status != 'OUT_OF_STOCK' THEN true ELSE false END as in_stock, p.total_available_qty as available_qty, p.avg_rating as average_rating, p.review_count as review_count, similarity(p.product_name, #{searchTerm}) AS relevance FROM hm_query.dim_product p
AND p.product_status = 'PUBLISHED'
AND similarity(p.product_name, #{searchTerm}) > 0.2
AND p.base_price >= #{minPrice} AND p.base_price <= #{maxPrice}
AND CASE WHEN #{inStock} = true THEN p.stock_status != 'OUT_OF_STOCK' ELSE p.stock_status = 'OUT_OF_STOCK' END
ORDER BY relevance DESC ${pagination}
